import os
from google.cloud import storage
import joblib

def load_model(bucket_name, source_blob_name):
    """Load the latest model version from cloud storage."""
    # Instantiate a Storage client
    gcs = storage.Client()
    
    # Get bucket
    bucket = gcs.get_bucket(bucket_name)

    # List blobs in the bucket and get latest modified time
    blob_list = list(bucket.list_blobs())
    blob_latest = max(blob_list, key=lambda b: b.updated)
    
    # Get name of the latest updated file from the blob
    source_blob_name = blob_latest.name

    # Download the blob to a local filename 
    destination_file_name = '/tmp/{}'.format(source_blob_name.split('/')[-1])
    bucket.blob(source_blob_name).download_to_filename(destination_file_name)
    
    # Load the downloaded model into memory and return it
    model = joblib.load(destination_file_name)
    return model

# Get BUCKET_NAME from environment variable
bucket_name = os.getenv('BUCKET_NAME')
model = load_model(bucket_name, 'path/to/model')